import osimport asyncioimport base64import jsonfrom io import BytesIOfrom flask import Flask, request, jsonifyfrom telethon import TelegramClientfrom tg_messages import get_chat_previewfrom tg_search import search_chatsfrom tg_send import send_messagesfrom tg_utils import get_chats_info, get_all_folders, update_chat_foldersapp = Flask(__name__)DEVICE_PARAMS = {    "device_model": "Samsung S23 Ultra",    "system_version": "Android 13",    "app_version": "9.6.1",    "lang_code": "en",    "system_lang_code": "en-US"}# {account_id: {'client': TelegramClient, 'api_id': int, 'api_hash': str, 'phone': str}}clients = {}# {account_id: {'api_id': int, 'api_hash': str, 'phone': str}}account_configs = {}loop = asyncio.new_event_loop()asyncio.set_event_loop(loop)def run_async(coro):    """Запускает корутину в существующем event loop."""    return loop.run_until_complete(coro)# ===========================================================================#  НОВЫЙ МЕТОД ИНИЦИАЛИЗАЦИИ (принимает массив аккаунтов)# ===========================================================================@app.route('/api/init', methods=['POST'])def init_accounts():    """    Инициализирует список аккаунтов.    Поддерживает два формата:    1. Массив: [{"id": 1, ...}, ...]    2. Объект с ключом "items": {"items": [{"id": 1, ...}, ...]}    """    try:        data = request.json        print(f"✅ INIT: {data}")        if data is None:            return jsonify({'error': 'Тело запроса пустое или не является JSON'}), 400        # Поддерживаем оба формата        if isinstance(data, dict) and 'items' in data:            accounts = data['items']        elif isinstance(data, list):            accounts = data        else:            return jsonify({                'error': 'Ожидается массив аккаунтов или объект с ключом "items"',                'received_type': str(type(data))            }), 400        if not isinstance(accounts, list):            return jsonify({                'error': 'Ожидается массив аккаунтов',                'received_type': str(type(accounts))            }), 400        if not accounts:            return jsonify({'error': 'Массив аккаунтов пуст'}), 400        print(f"✅ Получено {len(accounts)} аккаунтов")        results = []        errors = []        for account_data in accounts:            account_id = str(account_data.get('id'))            api_id = account_data.get('appId')            api_hash = account_data.get('appHash')            phone = account_data.get('phone')            description = account_data.get('description', '')            if not all([account_id, api_id, api_hash, phone]):                errors.append({                    'accountId': account_id if account_id else 'unknown',                    'error': 'Отсутствуют обязательные поля: id, appId, appHash, phone',                    'received': account_data                })                continue            try:                account_configs[account_id] = {                    'api_id': int(api_id),                    'api_hash': api_hash,                    'phone': phone,                    'description': description                }                if account_id in clients:                    old_client = clients[account_id]['client']                    try:                        if old_client.is_connected():                            run_async(old_client.disconnect())                    except Exception:                        pass                    del clients[account_id]                client = TelegramClient(                    f'session_{account_id}',                    int(api_id),                    api_hash,                    device_model=DEVICE_PARAMS["device_model"],                    system_version=DEVICE_PARAMS["system_version"],                    app_version=DEVICE_PARAMS["app_version"],                    lang_code=DEVICE_PARAMS["lang_code"],                    system_lang_code=DEVICE_PARAMS["system_lang_code"]                )                clients[account_id] = {                    'client': client,                    'api_id': int(api_id),                    'api_hash': api_hash,                    'phone': phone                }                results.append({                    'accountId': account_id,                    'phone': phone,                    'description': description,                    'status': 'ok'                })                print(f"✅ Аккаунт {account_id} ({phone}) инициализирован")            except Exception as e:                errors.append({                    'accountId': account_id,                    'error': str(e)                })                print(f"🔴 Ошибка инициализации аккаунта {account_id}: {e}")        return jsonify({            'status': 'completed',            'initialized': len(results),            'errors': len(errors),            'results': results,            'errorDetails': errors if errors else None        })    except Exception as e:        print(f"🔴 Ошибка инициализации: {e}")        return jsonify({'error': str(e)}), 500@app.route('/api/init/status', methods=['GET'])def get_init_status():    """Возвращает список всех инициализированных аккаунтов."""    result = []    for account_id, config in account_configs.items():        result.append({            'accountId': account_id,            'phone': config['phone'],            'description': config.get('description', ''),            'isConnected': account_id in clients and clients[account_id]['client'].is_connected()        })    return jsonify(result)# ===========================================================================#  ВСПОМОГАТЕЛЬНЫЕ ФУНКЦИИ# ===========================================================================def get_account_config(account_id):    """Возвращает настройки аккаунта по accountId."""    if account_id not in account_configs:        raise ValueError(f'Аккаунт {account_id} не инициализирован. Сначала вызовите /api/init')    return account_configs[account_id]async def get_or_create_client(account_id):    """    Получает существующего клиента или создаёт нового.    Использует сохранённые настройки из account_configs.    """    if account_id not in account_configs:        raise ValueError(f'Аккаунт {account_id} не инициализирован. Сначала вызовите /api/init')    config = account_configs[account_id]    api_id = config['api_id']    api_hash = config['api_hash']    phone = config['phone']    if account_id in clients:        client_data = clients[account_id]        client = client_data['client']        if not client.is_connected():            await client.connect()            if not await client.is_user_authorized():                await client.start(phone)        return client    print(f"🔄 Создание клиента для аккаунта {account_id}")    client = TelegramClient(        f'session_{account_id}',        api_id,        api_hash,        device_model=DEVICE_PARAMS["device_model"],        system_version=DEVICE_PARAMS["system_version"],        app_version=DEVICE_PARAMS["app_version"],        lang_code=DEVICE_PARAMS["lang_code"],        system_lang_code=DEVICE_PARAMS["system_lang_code"]    )    await client.connect()    if not await client.is_user_authorized():        await client.start(phone)        print(f"✅ Аккаунт {account_id} авторизован")    clients[account_id] = {        'client': client,        'api_id': api_id,        'api_hash': api_hash,        'phone': phone    }    return clientasync def ensure_connected(account_id):    """Проверяет и восстанавливает соединение для клиента по accountId."""    if account_id not in clients:        await get_or_create_client(account_id)    client_data = clients[account_id]    client = client_data['client']    if not client.is_connected():        print(f"🔄 Переподключение аккаунта {account_id}")        await client.connect()        if not await client.is_user_authorized():            phone = client_data['phone']            await client.start(phone)    return clientasync def get_avatar(client, entity):    """Асинхронное получение аватара без записи на диск."""    try:        buffer = BytesIO()        await client.download_profile_photo(entity, file=buffer)        if buffer.getvalue():            return base64.b64encode(buffer.getvalue()).decode('utf-8')    except Exception as e:        print(f"Avatar error: {e}")    return None# ===========================================================================#  ВСЕ ЭНДПОИНТЫ ПРИНИМАЮТ ТОЛЬКО accountId (без apiId, apiHash, phone)# ===========================================================================@app.route('/api/chats/all', methods=['GET'])def get_all_chats():    try:        account_id = request.args.get('accountId')        if not account_id:            return jsonify({'error': 'Не указан accountId'}), 400        if account_id not in account_configs:            return jsonify({'error': f'Аккаунт {account_id} не инициализирован. Сначала вызовите /api/init'}), 400        async def fetch():            client = await get_or_create_client(account_id)            result = []            count = 0            async for d in client.iter_dialogs():                username = getattr(d.entity, 'username', None)                if not username:                    phone_num = getattr(d.entity, 'phone', None)                    if phone_num:                        username = phone_num                result.append({                    'id': d.id,                    'name': d.name,                    'username': username,                    'avatar': await get_avatar(client, d.entity)                })                count += 1                if count % 50 == 0:                    print(f"Загружено {count} чатов...")                    await asyncio.sleep(0.3)            return result        data = run_async(fetch())        print(f"Всего загружено чатов: {len(data)}")        return jsonify(data)    except Exception as e:        print(f"Ошибка /api/chats/all: {e}")        return jsonify({'error': str(e)}), 500@app.route('/api/folders/update', methods=['POST'])def update_folders():    try:        data = request.json        print(f"🔵 Получены данные: {data}")        # Ищем accountId на верхнем уровне или внутри items        account_id = data.get('accountId')        # Если нет на верхнем уровне, пробуем достать из items        if account_id is None:            items = data.get('items', [])            if items and len(items) > 0:                account_id = items[0].get('tgAccountId')                print(f"🔵 accountId найден внутри items: {account_id}")        # Если всё ещё None, пробуем другие места        if account_id is None:            # Может быть в chatIds или других полях            account_id = data.get('tgAccountId')        folder_id = data.get('folderId')        chat_ids = data.get('chatIds', [])        add_to_folder = data.get('addOperationFlag', True)        # Если chat_ids пуст, пробуем достать id из items        if not chat_ids:            items = data.get('items', [])            for item in items:                chat_id = item.get('id')                if chat_id:                    chat_ids.append(chat_id)            # Также пробуем достать folderId из items            if folder_id is None and items:                folder_id = items[0].get('folderId')        # Приводим account_id к строке        account_id = str(account_id) if account_id is not None else None        if not account_id:            return jsonify({'error': 'Не указан accountId'}), 400        if account_id not in account_configs:            return jsonify({'error': f'Аккаунт {account_id} не инициализирован'}), 400        if not folder_id:            return jsonify({'error': 'Не указан ID папки'}), 400        if not chat_ids:            return jsonify({'error': 'Не указаны ID чатов'}), 400        client = run_async(get_or_create_client(account_id))        print(f"🔵 Обновление папки {folder_id}: {'добавление' if add_to_folder else 'удаление'} {len(chat_ids)} чатов")        result = run_async(update_chat_folders(client, folder_id, chat_ids, add_to_folder))        return jsonify(result)    except Exception as e:        print(f"🔴 Ошибка обновления папки: {e}")        return jsonify({'error': str(e)}), 500@app.route('/api/search', methods=['POST'])def search():    try:        data = request.json        print(f"🔵 Получены данные от Java: {data}")        tg_accounts = data.get('tgAccounts', [])        if not tg_accounts:            return jsonify({'error': 'Не указаны аккаунты'}), 400        params = {            'term': data.get('term', 'Java'),            'lastMessage': data.get('lastMessage', '').strip(),            'maxFoundCount': data.get('maxFoundCount', 10),            'minDiffDaysCount': data.get('minDiffDaysCount', 7),            'botType': data.get('botType', 'PERSONAL'),            'groupType': data.get('groupType', 'PERSONAL'),            'excludeChatIds': data.get('excludeChatIds', []),            'messagesCount': data.get('messagesCount', 0) or 0        }        print(f"🔵 Параметры поиска: {params}")        print(f"🔵 Количество аккаунтов: {len(tg_accounts)}")        all_results = []        for account in tg_accounts:            # Поддерживаем два формата            if isinstance(account, dict):                account_id = str(account.get('id'))            elif isinstance(account, (int, str)):                account_id = str(account)            else:                print(f"⚠️ Пропускаем аккаунт: неизвестный формат {type(account)}")                continue            if not account_id:                print("⚠️ Пропускаем аккаунт: нет id")                continue            if account_id not in account_configs:                print(f"⚠️ Пропускаем аккаунт {account_id}: не инициализирован. Сначала вызовите /api/init")                continue            print(f"🔍 Поиск в аккаунте: {account_id}")            try:                client = run_async(get_or_create_client(account_id))                found_chats = run_async(search_chats(client, params))                config = account_configs[account_id]                for chat in found_chats:                    chat['tgAccountId'] = account_id                    chat['accountPhone'] = config['phone']                all_results.extend(found_chats)                print(f"   Найдено чатов: {len(found_chats)}")            except Exception as e:                print(f"🔴 Ошибка при поиске в аккаунте {account_id}: {e}")                continue        if params['maxFoundCount'] and len(all_results) > params['maxFoundCount']:            all_results = all_results[:params['maxFoundCount']]        print(f"🔵 Всего найдено чатов: {len(all_results)}")        return jsonify(all_results)    except Exception as e:        print(f"🔴 Ошибка в search: {e}")        return jsonify([]), 500@app.route('/api/chat-preview', methods=['GET', 'POST'])@app.route('/api/chat-preview/', methods=['GET', 'POST'])def chat_preview():    """    Получение превью чата.    Поддерживает GET и POST методы.    GET: /api/chat-preview?chatId=123&accountId=1&limit=10    POST: тело запроса {"chatId": 123, "accountId": 1, "limit": 10}    """    try:        # Получаем параметры        if request.method == 'GET':            chat_id = request.args.get('chatId') or request.args.get('chat_id')            account_id = request.args.get('accountId')            limit = request.args.get('limit', default=None, type=int)        else:  # POST            data = request.json            if not data:                return jsonify({'error': 'Пустое тело запроса'}), 400            chat_id = data.get('chatId') or data.get('chat_id')            account_id = data.get('accountId')            limit = data.get('limit', None)        # Проверяем обязательные параметры        if not chat_id:            return jsonify({'error': 'Не указан chatId'}), 400        if not account_id:            return jsonify({'error': 'Не указан accountId'}), 400        # Проверяем инициализацию аккаунта        if account_id not in account_configs:            return jsonify({                'error': f'Аккаунт {account_id} не инициализирован. Сначала вызовите /api/init'            }), 400        # Получаем клиент        client = run_async(get_or_create_client(account_id))        # Преобразуем chat_id в int        try:            chat_id = int(chat_id)        except ValueError:            return jsonify({'error': f'Некорректный chatId: {chat_id}'}), 400        # Обрабатываем limit        if limit == 0:            limit = None        print(f"🔵 Получение превью чата {chat_id} для аккаунта {account_id}, limit={limit}")        result = run_async(get_chat_preview(client, chat_id, limit))        return jsonify(result)    except Exception as e:        print(f"🔴 Ошибка preview: {e}")        return jsonify({'messages': [], 'error': str(e)}), 500@app.route('/api/send_bulk_messages', methods=['POST'])def send_bulk_messages():    try:        data = request.json        print(f"🔵 Получены данные: {data}")        message_text = data.get('messageText', '')        delay = data.get('delaySeconds', 2)        only_new_chats = data.get('onlyNewChats', False)        if not message_text:            return jsonify({'error': 'Нет текста'}), 400        # Группируем чаты по tgAccountId        chats_by_account = {}        # Вариант 1: contacts.chatIds        contacts_data = data.get('contacts', {})        if contacts_data:            chat_ids_data = contacts_data.get('chatIds', [])            for chat_item in chat_ids_data:                chat_id = chat_item.get('id')                tg_account_id_raw = chat_item.get('tgAccountId')                tg_account_id = str(tg_account_id_raw) if tg_account_id_raw is not None else None                if not chat_id:                    print(f"⚠️ Пропускаем чат: нет id")                    continue                if not tg_account_id:                    print(f"⚠️ Пропускаем чат {chat_id}: нет tgAccountId")                    continue                if tg_account_id not in account_configs:                    print(f"⚠️ Пропускаем чат {chat_id}: аккаунт {tg_account_id} не инициализирован")                    continue                if tg_account_id not in chats_by_account:                    chats_by_account[tg_account_id] = []                chats_by_account[tg_account_id].append(chat_id)        # Вариант 2: contactUsernames (нужно искать чаты по username)        contact_usernames = data.get('contactUsernames', [])        if contact_usernames:            # Для username нужен tgAccountId на верхнем уровне или в каждом username            # Если не передан, берём из первого элемента или ошибка            default_tg_account_id = None            # Пробуем достать tgAccountId из запроса (если есть на верхнем уровне)            default_tg_account_id_raw = data.get('tgAccountId')            if default_tg_account_id_raw is not None:                default_tg_account_id = str(default_tg_account_id_raw)            else:                # Или пробуем из первого username (если есть tgAccountId в каждом)                pass            if default_tg_account_id is None:                return jsonify({'error': 'Для contactUsernames требуется tgAccountId'}), 400            if default_tg_account_id not in account_configs:                return jsonify({'error': f'Аккаунт {default_tg_account_id} не инициализирован'}), 400            # Получаем клиент для поиска username            client = run_async(get_or_create_client(default_tg_account_id))            run_async(ensure_connected(default_tg_account_id))            print(f"🔵 Поиск чатов по usernames: {contact_usernames}")            if default_tg_account_id not in chats_by_account:                chats_by_account[default_tg_account_id] = []            for username in contact_usernames:                try:                    clean_username = username.lstrip('@')                    entity = run_async(client.get_entity(clean_username))                    chat_id = entity.id                    chats_by_account[default_tg_account_id].append(chat_id)                    print(f"   ✅ Найден чат для {username}: {chat_id}")                except Exception as e:                    print(f"   ⚠️ Ошибка при поиске {username}: {e}")        if not chats_by_account:            return jsonify({'error': 'Нет чатов для отправки'}), 400        # Отправляем сообщения для каждого аккаунта        all_results = []        total_success = 0        total_skipped = 0        total_error = 0        for tg_account_id, chat_ids in chats_by_account.items():            print(f"🔵 Отправка от аккаунта {tg_account_id} в {len(chat_ids)} чатов")            client = run_async(get_or_create_client(tg_account_id))            run_async(ensure_connected(tg_account_id))            results = run_async(send_messages(client, chat_ids, message_text, delay, only_new_chats))            for result in results:                result['tgAccountId'] = tg_account_id                all_results.append(result)            success_count = len([r for r in results if r['status'] == 'success'])            skipped_count = len([r for r in results if r['status'] == 'skipped'])            error_count = len([r for r in results if r['status'] == 'error'])            total_success += success_count            total_skipped += skipped_count            total_error += error_count            print(f"   ✅ Отправлено: success={success_count}, skipped={skipped_count}, error={error_count}")        return jsonify({            'total': len(all_results),            'success': total_success,            'skipped': total_skipped,            'error': total_error,            'results': all_results        })    except Exception as e:        print(f"❌ Ошибка: {e}")        return jsonify({'error': str(e)}), 500@app.route('/api/export/<int:chat_id>', methods=['POST'])def export_chat(chat_id):    try:        data = request.json        account_id = data.get('accountId')        if not account_id:            return jsonify({'error': 'Не указан accountId'}), 400        if account_id not in account_configs:            return jsonify({'error': f'Аккаунт {account_id} не инициализирован. Сначала вызовите /api/init'}), 400        client = run_async(get_or_create_client(account_id))        async def export():            chat_name = str(chat_id)            async for d in client.iter_dialogs():                if d.id == chat_id:                    chat_name = d.name                    break            messages = []            async for m in client.iter_messages(chat_id, limit=5000):                messages.append({'id': m.id, 'date': str(m.date), 'text': m.text[:500] if m.text else None})            os.makedirs('exports', exist_ok=True)            filename = f'exports/{chat_name.replace("/", "_").replace(" ", "_")}.json'            with open(filename, 'w', encoding='utf-8') as f:                json.dump({                    'chat_id': chat_id,                    'chat_name': chat_name,                    'total_messages': len(messages),                    'messages': messages                }, f, ensure_ascii=False, indent=2)            return {'filename': filename, 'total': len(messages)}        result = run_async(export())        return jsonify(result)    except Exception as e:        return jsonify({'error': str(e)}), 500@app.route('/api/folders', methods=['GET', 'POST'])  # <-- добавляем GETdef get_folders():    try:        # Получаем accountId из разных мест        if request.method == 'GET':            account_id = request.args.get('accountId')        else:  # POST            data = request.json            account_id = data.get('accountId')        if not account_id:            return jsonify({'error': 'Не указан accountId'}), 400        if account_id not in account_configs:            return jsonify({'error': f'Аккаунт {account_id} не инициализирован'}), 400        client = run_async(get_or_create_client(account_id))        folders = run_async(get_all_folders(client))        return jsonify(folders)    except Exception as e:        print(f"❌ Ошибка получения папок: {e}")        return jsonify([]), 500@app.route('/api/chats/info', methods=['POST'])def get_chats_info_endpoint():    try:        data = request.json        account_id = data.get('accountId')        if not account_id:            return jsonify({'error': 'Не указан accountId'}), 400        if account_id not in account_configs:            return jsonify({'error': f'Аккаунт {account_id} не инициализирован. Сначала вызовите /api/init'}), 400        client = run_async(get_or_create_client(account_id))        chat_ids = data.get('chat_ids', [])        if not chat_ids:            return jsonify({'error': 'Нет ID чатов'}), 400        print(f"🔵 Запрос информации о {len(chat_ids)} чатах")        results = run_async(get_chats_info(client, chat_ids))        return jsonify({            'total': len(chat_ids),            'success': len([r for r in results if r.get('name') is not None]),            'error': len([r for r in results if r.get('error')]),            'results': results        })    except Exception as e:        print(f"🔴 Ошибка в /api/chats/info: {e}")        return jsonify({'error': str(e)}), 500if __name__ == '__main__':    print("🚀 Сервер на http://localhost:8081")    print("📌 Сначала инициализируйте аккаунты: POST /api/init (массив аккаунтов)")    app.run(debug=False, port=8081, threaded=False)